import React, { Fragment, Component } from 'react';
import PropTypes from 'prop-types';
import { connect } from 'react-redux';
import { Link } from 'react-router-dom';
import { withStyles, Grid, Typography, Dialog, Zoom, IconButton } from '@material-ui/core';
import CloseIcon from '@material-ui/icons/Close';
import PlayArrowIcon from '@material-ui/icons/PlayArrow';
import Slider from 'react-slick';
import {
  getMovies,
  getCinemas,
  getShowtimes,
  getMovieSuggestion,
  getOffers
} from '../../../store/actions';
import MovieCarousel from '../components/MovieCarousel/MovieCarousel';
import MovieBanner from '../components/MovieBanner/MovieBanner';
import OfferBanner from '../components/OfferBanner/OfferBanner';
import CinemaCard from '../components/CinemaCard/CinemaCard';
import QuickBookBar from '../components/QuickBookBar/QuickBookBar';
import ExperiencesSection from '../components/ExperiencesSection/ExperiencesSection';
import OffersSection from '../components/OffersSection/OffersSection';
import FoodSection from '../components/FoodSection/FoodSection';
import { filterPrimaryCinemas } from '../../../utils/cinemaListing';
import styles from './styles';
import 'slick-carousel/slick/slick.css';
import 'slick-carousel/slick/slick-theme.css';
import ReactPlayer from 'react-player';

class HomePage extends Component {
  state = { activeTab: 'nowShowing', homeBanner: null, trailerModalOpen: false, activeTrailerUrl: null };

  componentDidMount() {
    const {
      movies,
      cinemas,
      showtimes,
      suggested,
      getMovies,
      getCinemas,
      getShowtimes,
      getMovieSuggestion,
      getOffers,
      user
    } = this.props;
    if (!movies.length) getMovies();
    if (!cinemas.length) getCinemas();
    if (!showtimes.length) getShowtimes();
    getOffers();
    if (user) {
      if (!suggested.length) getMovieSuggestion(user.username);
    }
    this.fetchHomeBannerSetting();
    this.fetchUserLocation();
  }

  fetchHomeBannerSetting = async () => {
    try {
      const response = await fetch('/settings/homePageBanner');
      if (!response.ok) return;
      const data = await response.json();
      const value = data && data.value ? data.value : null;
      this.setState({ homeBanner: value });
    } catch (e) {
      // keep default hero if setting is missing/unavailable
    }
  };

  fetchUserLocation = async () => {
    try {
      const { getUserLocation } = await import('../../../utils/geolocation');
      const { getCinemaCoordinates, calculateDistance } = await import('../../../utils/distance');
      
      const location = await getUserLocation();
      this.setState({ userLocation: location });
      
      // Calculate nearest cinema when cinemas are available
      this.calculateNearestCinema(location);
    } catch (error) {
      console.log('Location access denied or unavailable', error);
    }
  };

  calculateNearestCinema = (location = this.state.userLocation) => {
    if (!location || !this.props.cinemas.length) return;
    
    let nearest = null;
    let minDistance = Infinity;
    
    const { getCinemaCoordinates, calculateDistance } = require('../../../utils/distance');
    
    this.props.cinemas.forEach(cinema => {
      const coords = getCinemaCoordinates(cinema);
      if (coords) {
        const dist = calculateDistance(location.latitude, location.longitude, coords.latitude, coords.longitude);
        if (dist < minDistance) {
          minDistance = dist;
          nearest = { ...cinema, distance: dist.toFixed(1) };
        }
      }
    });
    
    if (nearest) {
      this.setState({ nearestCinema: nearest });
    }
  };

  componentDidUpdate(prevProps) {
    if (this.props.user !== prevProps.user) {
      this.props.user &&
        this.props.getMovieSuggestion(this.props.user.username);
    }
    if (this.props.cinemas !== prevProps.cinemas && this.state.userLocation) {
      this.calculateNearestCinema();
    }
  }

  scrollTo = id => {
    const el = document.getElementById(id);
    if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
    this.setState({ activeTab: id });
  };

  handleOpenTrailer = (url) => {
    this.setState({ trailerModalOpen: true, activeTrailerUrl: url });
  };

  handleCloseTrailer = () => {
    this.setState({ trailerModalOpen: false, activeTrailerUrl: null });
  };

  render() {
    const {
      classes,
      movies,
      cinemas,
      randomMovie,
      comingSoon,
      nowShowing,
      suggested,
      offers
    } = this.props;
    const { activeTab, homeBanner, trailerModalOpen, activeTrailerUrl, nearestCinema } = this.state;
    const heroMovies = (nowShowing && nowShowing.length ? nowShowing : movies).slice(0, 3);

    // Combine movies and top 2 offers for the banner
    const topOffers = (offers || []).slice(0, 2);
    const heroItems = [
      ...heroMovies.map(movie => ({ type: 'movie', data: movie })),
      ...topOffers.map(offer => ({ type: 'offer', data: offer }))
    ];
    const primaryCinemas = filterPrimaryCinemas(cinemas);
    const moviePrices = (movies || []).map(m => Number(m.ticketPrice)).filter(p => p > 0);
    const minMoviePrice = moviePrices.length ? Math.min(...moviePrices) : 0;

    const heroSettings = {
      dots: true,
      arrows: false,
      infinite: heroItems.length > 1,
      speed: 500,
      slidesToShow: 1,
      slidesToScroll: 1,
      autoplay: heroItems.length > 1,
      autoplaySpeed: 5000,
      pauseOnHover: true
    };

    const TABS = [
      { id: 'nowShowing', label: '🎬 Now Showing' },
      { id: 'suggested', label: 'Next Change' },
      { id: 'comingSoon', label: '🗓 Coming Soon' },
      { id: 'allMovies', label: '🎥 All Movies' },
      { id: 'cinemas', label: '🏛 Cinemas' },
    ];

    return (
      <Fragment>
        {/* ── Hero Banner ── */}
        <div className={classes.heroCarousel}>
          {homeBanner && homeBanner.enabled && homeBanner.banners && homeBanner.banners.length ? (
            <Slider {...heroSettings}>
              {homeBanner.banners.map((banner, idx) => (
                <div key={idx}>
                  <div className={classes.customHero}>
                    <div
                      className={classes.customHeroBackdrop}
                      style={{ backgroundImage: `url("${banner.imageUrl}")` }}
                    />
                    <div className={classes.customHeroOverlay} />
                    <div className={classes.customHeroContent}>
                      <Typography className={classes.customHeroTitle} variant="h2">
                        {banner.title || 'Welcome to M2K Cinemas'}
                      </Typography>
                      {!!banner.subtitle && (
                        <Typography className={classes.customHeroSubtitle} variant="body1">
                          {banner.subtitle}
                        </Typography>
                      )}
                      {!!banner.ctaText && !!banner.ctaLink && (
                        <Link className={classes.customHeroCta} to={banner.ctaLink}>
                          {banner.ctaText}
                        </Link>
                      )}
                    </div>
                    {(banner.videoUrl || banner.trailerPosterUrl) && (
                      <div className={classes.trailerVideoWrapper}>
                        {banner.videoUrl && (
                          <div 
                            className={classes.trailerOverlayClick}
                            onClick={() => this.handleOpenTrailer(banner.videoUrl)}
                            title="Play Trailer"
                          >
                            <PlayArrowIcon className={classes.playIcon} />
                          </div>
                        )}
                        {banner.trailerPosterUrl ? (
                          <img 
                            src={banner.trailerPosterUrl} 
                            alt="Trailer Poster"
                            style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
                          />
                        ) : (
                          <ReactPlayer
                            url={banner.videoUrl}
                            light={true}
                            width="100%"
                            height="100%"
                            style={{ pointerEvents: 'none' }}
                          />
                        )}
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </Slider>
          ) : heroItems.length ? (
            <Slider {...heroSettings}>
              {heroItems.map((item, idx) => (
                <div key={item.data._id || idx}>
                  {item.type === 'movie' ? (
                    <MovieBanner movie={item.data} height="65vh" />
                  ) : (
                    <OfferBanner offer={item.data} height="65vh" />
                  )}
                </div>
              ))}
            </Slider>
          ) : (
            <MovieBanner movie={randomMovie} height="65vh" />
          )}
        </div>

        {nearestCinema && (
          <div style={{ backgroundColor: '#111', padding: '12px 20px', textAlign: 'center', borderBottom: '1px solid #333' }}>
            <Typography variant="body1" style={{ color: '#fff', fontWeight: 500 }}>
              <span style={{ color: '#b72429', marginRight: 4 }}>📍 Nearest to you:</span> 
              <Link to={`/cinemas`} style={{ color: '#fff', textDecoration: 'underline' }}>
                {nearestCinema.name} ({nearestCinema.distance} km away)
              </Link>
            </Typography>
          </div>
        )}

        {/* ── Quick Book Bar ── */}
        <QuickBookBar movies={movies} cinemas={primaryCinemas} />

        {/* ── Section Tabs ── */}
        <div className={classes.tabsBar}>
          {TABS.map(tab => (
            <button
              key={tab.id}
              className={`${classes.tab} ${activeTab === tab.id ? classes.tabActive : ''}`}
              onClick={() => this.scrollTo(tab.id)}
            >
              {tab.label}
            </button>
          ))}
        </div>

        {/* ── Now Showing ── */}
        {!!(nowShowing && nowShowing.length) && (
          <div id="nowShowing" className={classes.sectionWrapper}>
            <MovieCarousel
              carouselClass={classes.carousel}
              title="Now Showing"
              to="/movie/category/nowShowing"
              autoScroll
              autoScrollSpeed={3200}
              movies={nowShowing}
            />
          </div>
        )}

        {/* ── Suggested / Next Change ── */}
        {!!(suggested && suggested.length) && (
          <div id="suggested" className={classes.sectionWrapper}>
            <MovieCarousel
              carouselClass={classes.carousel}
              title="Next Change"
              movies={suggested}
            />
          </div>
        )}

        {/* ── Coming Soon ── */}
        {!!(comingSoon && comingSoon.length) && (
          <div id="comingSoon" className={classes.sectionWrapper}>
            <MovieCarousel
              carouselClass={classes.carousel}
              title="Coming Soon"
              to="/movie/category/comingSoon"
              autoScroll
              autoScrollSpeed={3600}
              movies={comingSoon}
            />
          </div>
        )}

        {/* ── All Movies ── */}
        {!!(movies && movies.length) && (
          <div id="allMovies" className={classes.sectionWrapper}>
            <MovieCarousel
              carouselClass={classes.carousel}
              title="All Movies"
              to="/movies"
              autoScroll
              autoScrollSpeed={3400}
              movies={movies}
            />
          </div>
        )}

        {/* ── PVR Experiences ── */}
        <ExperiencesSection />

        {/* ── Offers For You ── */}
        <OffersSection />

        {/* ── Food & Combos ── */}
        <FoodSection />

        {/* ── Cinemas ── */}
        <div id="cinemas" className={classes.cinemasSection}>
          <div className={classes.cinemasTitleBlock}>
            <Typography className={classes.sectionTitle} variant="h2">
              Our Cinemas
            </Typography>
            <div className={classes.titleAccent} />
          </div>
          <Grid container spacing={3}>
            {primaryCinemas.map(cinema => (
              <Grid key={cinema._id} item xs={12} sm={6} md={4} lg={3}>
                <CinemaCard cinema={cinema} linkToDetails minMoviePrice={minMoviePrice} />
              </Grid>
            ))}
          </Grid>
        </div>

        {/* Footer is handled by PublicLayout */}
        
        {/* ── Trailer Modal ── */}
        <Dialog
          open={trailerModalOpen}
          onClose={this.handleCloseTrailer}
          TransitionComponent={Zoom}
          maxWidth="md"
          fullWidth
          PaperProps={{
            style: {
              backgroundColor: '#000',
              boxShadow: 'none',
              overflow: 'hidden',
              borderRadius: 16,
            }
          }}
        >
          <IconButton 
            onClick={this.handleCloseTrailer} 
            style={{ position: 'absolute', top: 8, right: 8, zIndex: 10, color: '#fff', background: 'rgba(0,0,0,0.5)' }}
          >
            <CloseIcon />
          </IconButton>
          <div style={{ position: 'relative', paddingTop: '56.25%', width: '100%' }}>
            <ReactPlayer
              url={activeTrailerUrl}
              playing={trailerModalOpen}
              controls={true}
              width="100%"
              height="100%"
              style={{ position: 'absolute', top: 0, left: 0 }}
            />
          </div>
        </Dialog>
      </Fragment>
    );
  }
}

HomePage.propTypes = {
  className: PropTypes.string,
  classes: PropTypes.object.isRequired,
  history: PropTypes.object.isRequired,
  movies: PropTypes.array.isRequired,
  latestMovies: PropTypes.array.isRequired
};

const mapStateToProps = ({ movieState, cinemaState, showtimeState, authState, offerState }) => ({
  movies: movieState.movies,
  cinemas: cinemaState.cinemas,
  randomMovie: movieState.randomMovie,
  latestMovies: movieState.latestMovies,
  comingSoon: movieState.comingSoon,
  nowShowing: movieState.nowShowing,
  showtimes: showtimeState.showtimes,
  suggested: movieState.suggested,
  offers: offerState.offers,
  user: authState.user
});

const mapDispatchToProps = { getMovies, getCinemas, getShowtimes, getMovieSuggestion, getOffers };

export default connect(
  mapStateToProps,
  mapDispatchToProps
)(withStyles(styles)(HomePage));

